const modal = document.querySelector('.my-modal');

function openModal() {
  modal.style.display = 'block';

  // Move the user's cursor physically into the modal
  const firstInput = modal.querySelector('input');
  firstInput.focus();
}

// Trap focus: If they hit Tab on the last button, loop back to the first input.
modal.addEventListener('keydown', (e) => {
  if (e.key === 'Tab') {
    // Complex JS logic here to prevent focus from leaving the modal...
  }
});

